// UUID generator
import 'package:flutter/foundation.dart';

class MyUUID {
  static String uuid = '1';

  MyUUID(); //constructor

  static void gen() => ++uuid;

  static void reset(){
    uuid = '1';
  }

  // Generate random UUID - returns hexadecimal string
  static String generate() {
     int length = 8;

     for (int i=0 ; i<length ;i++)
        uuid+=(Random().nextInt(9).toString());

      return "0x$uuid";
   }
}

